arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 42
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
$FOUND = $false

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A: "Copilot's findings"
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Copilot.s findings")) | .id' 2>$null
    if ($reviews) { Write-Host "Found via Strategy A"; $FOUND = $true; break }

    # Strategy B: "Pull request overview"
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Pull request overview")) | .id' 2>$null
    if ($reviews) { Write-Host "Found via Strategy B"; $FOUND = $true; break }

    # Strategy C: copilot-pull-request-reviewer bot
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | .id' 2>$null
    if ($reviews) { Write-Host "Found via Strategy C"; $FOUND = $true; break }

    # Strategy D: Line-level comments from "Copilot"
    $comments = gh api "/repos/$REPO/pulls/$PR/comments" --jq '.[] | select(.user.login == "Copilot") | .id' 2>$null
    if ($comments) { Write-Host "Found via Strategy D"; $FOUND = $true; break }

    Write-Host "Polling... elapsed ${ELAPSED}s"
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($FOUND) {
    Write-Host "Copilot review found!"
    # Get the full review details
    gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer|Copilot")) | {id: .id, body: .body, state: .state, user: .user.login}'
} else {
    Write-Host "TIMEOUT: Copilot review not found after ${TIMEOUT}s"
}

